/* UsimOrdAddrMapper.usimOrdAddrList */ SELECT SEQ , ORGN_ID , F_GET_AGENT_NM(A.ORGN_ID) AS ORGN_NM , AREA_NM , MNG_NM , MNG_NM AS MASK_MNG_NM , TEL_FN1 , TEL_MN1 , TEL_RN1 , TEL_FN2 , TEL_MN2 , TEL_RN2 , DECODE(TEL_FN1, NULL, '', TEL_FN1 || '-' || TEL_MN1 || '-' || TEL_RN1) MNG_PHN , DECODE(TEL_FN2, NULL, '', TEL_FN2 || '-' || TEL_MN2 || '-' || TEL_RN2) MNG_MBLPHN , USE_YN , POST , ADDR , ADDR_BJD , ADDR_DTL , ADDR_DTL AS MASK_ADDR_DTL , FN_GET_USRNM(RVISN_ID) AS USR_NM
FROM MSP_M2M_ADDR A WHERE 1=1
AND A.ORGN_ID = #{orgnId, jdbcType=VARCHAR}
AND NVL(A.DEL_YN,'N') = 'N'
ORDER BY ORGN_ID

