(
    SEQ
    , ORGN_ID
    , AREA_NM
    , MNG_NM
	, TEL_FN1
	, TEL_MN1
	, TEL_RN1
	, TEL_FN2
	, TEL_MN2
	, TEL_RN2
    , USE_YN
    , POST
    , ADDR
    , ADDR_BJD
    , ADDR_DTL
    , REGST_ID
    , REGST_DTTM
    , RVISN_ID
    , RVISN_DTTM
    , DEL_YN
)
VALUES
(
	SQ_MSP_M2M_ADDR_01.NEXTVAL
  , #{orgnId, jdbcType=VARCHAR}
  , #{areaNm, jdbcType=VARCHAR}
  , #{mngNm, jdbcType=VARCHAR}

  , #{telFn1, jdbcType=VARCHAR}
