  , #{useYn, jdbcType=VARCHAR}

  , #{post, jdbcType=VARCHAR}
  , #{addr, jdbcType=VARCHAR}
  , #{addrBjd, jdbcType=VARCHAR}
  , #{addrDtl, jdbcType=VARCHAR}

  , #{sessionUserId, jdbcType=VARCHAR}
  , SYSDATE
  , #{sessionUserId, jdbcType=VARCHAR}
  , SYSDATE
  , 'N'

)

